const i = items[0].json;
const task = i.task || 'render_long';
const project_id = i.project_id;
const schema = i.schema || 'music_ai';
if (!project_id) { throw new Error('project_id is required'); }

const payload = { task, project_id, schema };
if (task === 'render_long') {
  payload.cover_path = i.cover_path || 'assets/cover.png';
  payload.audio_path = i.audio_path || 'assets/audio.mp3';
  payload.output_path = i.output_path || 'outputs/video_long.mp4';
} else if (task === 'render_short') {
  payload.video_path = i.video_path || 'outputs/video_long.mp4';
  payload.start = i.start || '00:00:00';
  payload.end = i.end || '00:00:30';
  payload.output_path = i.output_path || 'outputs/short_01.mp4';
} else if (task === 'burn_subtitles') {
  payload.video_path = i.video_path || 'outputs/video_long.mp4';
  payload.subtitle_path = i.subtitle_path || 'assets/subtitles.srt';
  payload.output_path = i.output_path || 'outputs/video_subbed.mp4';
} else {
  throw new Error('Unknown task: ' + task);
}

const bodyJson = JSON.stringify(payload);
return [{ json: { bodyJson, task, project_id, output_path: payload.output_path } }];

const r = items[0].json || {};
const meta = $('Build Payload').first().json;
return [{ json: {
  jobId: r.id || null,
  status: r.status || 'queued',
  project_id: meta.project_id,
  task: meta.task,
  output_path: meta.output_path
} }];
